package day02;

public class ArithmeticOperatorPractice {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		// Ex1
		int a1 = 10;
		int b1 = 15;

		int c1 = a1 + b1;
		System.out.println("By doing sum of a and b, value of c will be: " + c1);

		// Ex2
		int a2 = 90;
		int b2 = 15;

		int c2 = a2 - b2;
		System.out.println("By doing subtraction of a and b, value of c will be: " + c2);

		// Ex3
		int a3 = 30;
		int b3 = 10;

		int c3 = a3 * b3;
		System.out.println("By doing multiplication of a and b, value of c will be: " + c3);

		// Ex4
		int a4 = 40;
		int b4 = 10;

		int c4 = a4 / b4;
		System.out.println("By doing division of a and b, value of c will be: " + c4);
		c4 = a4 % b4;
		System.out.println("By doing ModuloDivision of a and b, value of c will be: " + c4);

	}

}
